+	case "witness", "refinery":
+		return fmt.Sprintf("gt-%s-%s", parsed.RigName, parsed.RoleType)
+	case "crew":
+		return fmt.Sprintf("gt-%s-crew-%s", parsed.RigName, parsed.AgentName)
+	case "polecat":
